import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

// The gateway has no CORS layer; the dev/preview servers proxy /api/* to it instead.
const proxy = {
  '/api': {
    target: process.env.GATEWAY_URL || 'http://localhost:3000',
    changeOrigin: true,
    rewrite: (path) => path.replace(/^\/api/, ''),
  },
};

export default defineConfig({
  plugins: [react()],
  server: { port: 5173, proxy, allowedHosts: ['dqplus.ddns.net'] },
  preview: { port: 5173, proxy, allowedHosts: ['dqplus.ddns.net'] },
});
const express = require("express");
const swaggerUi = require("swagger-ui-express");
const authRouter = require("./routes/auth.routes");
const profileRouter = require("./routes/profile.routes");
const errorHandler = require("./middleware/errorHandler");
const { sequelize } = require("./models");
const swaggerSpec = require("./config/swagger");

const app = express();

const corsOrigin = process.env.CORS_ORIGIN
  ? process.env.CORS_ORIGIN.split(",")
  : /^https?:\/\/(dqplus\.ddns\.net|localhost|127\.0\.0\.1)(:\d+)?$/;
app.use(cors({ origin: corsOrigin }));
app.use(express.json());

app.get("/health", async (req, res) => {
  try {
    await sequelize.authenticate();
    res.json({ status: "ok", db: "connected" });
  } catch (err) {
    res.status(503).json({ status: "degraded", db: "unavailable" });
  }
});

app.use("/docs", swaggerUi.serve, swaggerUi.setup(swaggerSpec));
app.use("/auth", authRouter);
app.use("/profiles", profileRouter);

app.use((req, res) => {
  res.status(404).json({ error: "Not found" });
});

app.use(errorHandler);

module.exports = app;
